import{_ as a,o as t,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Movable Ink - Email","description":"","frontmatter":{"title":"Movable Ink - Email","slug":"movable-ink-email"},"headers":[],"relativePath":"marketer-hub/movable-ink-email.md","filePath":"marketer-hub/movable-ink-email.md"}'),r={name:"marketer-hub/movable-ink-email.md"};function l(n,e,s,h,p,c){return t(),i("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This guide will walk you through how to setup your email campaigns with <a href="https://movableink.com" target="_blank" rel="noreferrer"><strong>Movable Ink</strong></a> using Branch&#39;s Email feature to automatically convert your email links into <strong>multi-platform deep links</strong>.</p><p>Branch allows you to automatically convert your email links into multi-platform deep links that take users directly to content in the app on mobile devices, while still maintaining the same web experience for desktop and mobile users without the app.</p><p>When a link is clicked by a user without the app, it will route that user to the original web URL (including on desktop). When a link is clicked by a user with your app, it will direct that user into the relevant in-app content regardless of platform or email client.</p><div class="warning custom-block"><p class="custom-block-title">Movable Ink Link Format</p><p>Please make sure that you are using web URLs on the Movable Ink platform rather than URI schema.</p></div><h2 id="setup-email-link" tabindex="-1">Setup Email Link <a class="header-anchor" href="#setup-email-link" aria-label="Permalink to &quot;Setup Email Link&quot;">​</a></h2><h3 id="configure-your-esp" tabindex="-1">Configure Your ESP <a class="header-anchor" href="#configure-your-esp" aria-label="Permalink to &quot;Configure Your ESP&quot;">​</a></h3><p>You can use Movable Ink personalization links with any ESP, so before we start to configure Movable Ink, please find your ESP in this list - <a href="./email-partners-list.html">Email Partners List</a> - and follow the integration guide to make sure that you have configured and enabled the integration.</p><h3 id="setup-link-behavior" tabindex="-1">Setup Link Behavior <a class="header-anchor" href="#setup-link-behavior" aria-label="Permalink to &quot;Setup Link Behavior&quot;">​</a></h3><p>Once you have completed the ESP configuration, you can start adding Movable Ink links to the email body.</p><ol><li><p>Please check this checkbox to tell Movable Ink that you are using Branch. Then Movable Ink can automatically append all required parameters.</p></li><li><p>Once enabled, you will see the option to <strong>Copy Branch URL</strong>. This will copy creative tags for email and mobile channels.</p></li><li><p>At the end of the Branch Link, make sure to append the <code>?deep_link=true</code> query parameter to the end of the URL.</p></li><li><p>Take the URL from step 3 (with the appended query parameter) and add it in the Moveable Ink UI to generate a new Moveable Ink link.</p></li><li><p>Append the <code>follow_redirect=true</code> query parameter to the end of the generated Moveable Ink link from step 4. This should be added as a <a href="./personalization.html#required-redirect-parameter">normal query parameter</a>.</p></li><li><p>Take the URL from step 5 and add it to the Iterable email template.</p></li></ol><h3 id="qa-testing-for-movable-ink" tabindex="-1">QA Testing for Movable Ink <a class="header-anchor" href="#qa-testing-for-movable-ink" aria-label="Permalink to &quot;QA Testing for Movable Ink&quot;">​</a></h3><p>To test tracking, take the finalized Branch URL that is placed within your email template and click the URL.</p><p>After the URL is clicked, you’ll check to make sure the clicks are recorded within the Movable Ink campaign dashboard.</p><p>If clicks are recording, then the setup is successful!</p>',15)])])}const m=a(r,[["render",l]]);export{d as __pageData,m as default};
